create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,owner_name text default '',phone text default '',email text default '',company_name text default '',company_phone text default '',business_number text default '',subscription_status text default 'trial',trial_started_at timestamptz default now(),created_at timestamptz default now());create table if not exists public.quotes (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,customer_name text default '',customer_phone text default '',move_date date,from_address text default '',to_address text default '',quote_data jsonb default '{}'::jsonb,created_at timestamptz default now());alter table public.profiles enable row level security;alter table public.quotes enable row level security;create policy "profiles own select" on public.profiles for select using (auth.uid()=id);create policy "profiles own insert" on public.profiles for insert with check (auth.uid()=id);create policy "profiles own update" on public.profiles for update using (auth.uid()=id);create policy "quotes own all" on public.quotes for all using (auth.uid()=user_id) with check (auth.uid()=user_id);